function report = runSyntheticHeightVisualization(scene, options)
%RUNSYNTHETICHEIGHTVISUALIZATION Run the shared dense synthetic diagnostic.
%
% This implementation is shared by the committed degraded fixtures and the
% ignored raster-texture dataset. It preserves exact camera geometry while
% reporting raw ZNCC, guarded parabolic refinement, frozen physical-height
% SGM, exact transported spin-2 T3, the frozen robust hybrid, confidence,
% truth errors, alignment residuals, and timing as separate products.
%
% CpuImplementation="optimized" uses dense single-precision ZNCC, dense
% exact-transport T3, and vectorized SGM. CpuImplementation="reference"
% retains the sparse CPU path and path-wise SGM for small-scene regression.
% T3 is volume-free by default, while ZNCC is retained because SGM consumes
% it. The frozen hybrid has weights [1,0] and selects exactly raw ZNCC.
%
% Traceability: algo/main.tex Algorithm 1; Secs. 6.2, 8.4, 10.4--10.5,
% 11.2--11.4, and 14.6; Eqs. (71)--(76) and (121)--(133);
% implementation plan Stage C7.

arguments
    scene (1, 1) struct {mustBeVisualizationScene}
    options.Display (1, 1) logical = true
    options.UseParallel (1, 1) logical = false
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [128, 128]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.HeightLabelMode (1, 1) string ...
        {mustBeMember(options.HeightLabelMode, ...
        ["observability", "three-plane"])} = "observability"
    options.CostCurveFraction (1, 2) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.CostCurveFraction, 0), mustBeLessThanOrEqual( ...
        options.CostCurveFraction, 1)} = [0.5, 0.5]
    options.StoreResearchCostVolumes (1, 1) logical = false
    options.CpuImplementation (1, 1) string ...
        {mustBeMember(options.CpuImplementation, ...
        ["optimized", "reference"])} = "optimized"
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
end
totalTimer = tic;
renderer = scene.Renderer;
split = scene.Configuration;
pair = scene.Pair;
truthHeight = scene.TruthHeightMetres;
truthCorrespondence = scene.TruthCorrespondenceXY;
truthValid = scene.TruthValid;

timer = tic;
geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
levels = 2 ^ renderer.BitDepth - 1;
referenceDouble = double(pair.ReferenceImage) ./ levels;
movingDouble = double(pair.MovingImage) ./ levels;
referenceWorking = cast(pair.ReferenceImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision);
movingWorking = cast(pair.MovingImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision);
curve = HeightCostCurve(geometry, referenceWorking, movingWorking, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    WorkingPrecision=options.WorkingPrecision);
dense = DenseHeightSweep(curve);
[z, spacing, medianObservability, labelDesign] = labels( ...
    geometry, truthHeight, truthValid, scene.SearchRangeMetres, ...
    scene.TargetMotionPerLabelPixels, options.HeightLabelMode);
prepareSeconds = toc(timer);

minimumSupport = double(split.dense.minimumSupportFraction);
timer = tic;
if options.CpuImplementation == "optimized"
    products = ["LabelIndex", "BestCost", "SecondBestCost", ...
        "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
        "Observability", "Correspondence", "SelectedHeightByChannel"];
    wta = dense.runZnccOptimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=true, UseParallel=options.UseParallel, ...
        NumWorkers=options.NumWorkers, ...
        MaximumPendingTiles=options.MaximumPendingTiles, ...
        WorkingPrecision=options.WorkingPrecision, Products=products, ...
        MinimumSupportFraction=minimumSupport);
else
    wta = dense.runTiled(z, Channel="Zncc", Channels="Zncc", ...
        TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=true, UseParallel=options.UseParallel, ...
        NumWorkers=options.NumWorkers, ...
        MinimumSupportFraction=minimumSupport);
end
sweepSeconds = toc(timer);

timer = tic;
if options.CpuImplementation == "optimized"
    t3Products = ["LabelIndex", "BestCost", "SecondBestCost", ...
        "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
        "Confidence", "Support", "Observability", "Correspondence"];
    t3 = dense.runT3Optimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=options.StoreResearchCostVolumes, ...
        UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
        MaximumPendingTiles=options.MaximumPendingTiles, ...
        WorkingPrecision=options.WorkingPrecision, Products=t3Products, ...
        MinimumSupportFraction=minimumSupport);
else
    t3 = dense.runTiled(z, Channel="Spin2T3", Channels="Spin2T3", ...
        TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=options.StoreResearchCostVolumes, ...
        UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
        MinimumSupportFraction=minimumSupport);
end
hybridModel = ZnccSpin2Hybrid.fromStruct(split.frozenHybrid);
if hybridModel.Spin2Weight ~= 0
    error("runSyntheticHeightVisualization:HybridNeedsStreaming", ...
        ["The frozen hybrid has a nonzero T3 weight. Add an explicitly " ...
        "tested streamed fused-channel selector before using it here."]);
end
hybrid = scaledZnccSelection(wta, hybridModel.ZnccScale);
t3Seconds = toc(timer);

timer = tic;
refined = HeightSublabelRefiner.refine(z, wta.LabelIndex, ...
    wta.PreviousLabelCost, wta.BestCost, wta.NextLabelCost, ...
    ValidMask=wta.Valid);
refinedProjection = dense.projectHeightMap( ...
    refined.RefinedHeightMetres, refined.Valid);
refineSeconds = toc(timer);

timer = tic;
p = split.frozenSgm;
if options.CpuImplementation == "optimized"
    sgm = HeightSgm.aggregateVectorized(wta.CostVolume, z, ...
        PenaltyPerMetre=double(p.penaltyPerMetre), ...
        MaximumPenalty=double(p.maximumPenalty), ...
        DirectionCount=double(p.directionCount));
    sgmImplementation = "vectorized";
else
    sgm = HeightSgm.aggregate(wta.CostVolume, z, ...
        PenaltyPerMetre=double(p.penaltyPerMetre), ...
        MaximumPenalty=double(p.maximumPenalty), ...
        DirectionCount=double(p.directionCount));
    sgmImplementation = "reference";
end
sgmProjection = dense.projectHeightMap(sgm.HeightMetres, sgm.Valid);
sgmSeconds = toc(timer);

timer = tic;
calibrator = HeightConfidenceCalibrator.fromStruct( ...
    split.frozenConfidence);
confidence = calibrator.predict(wta.CostMargin, ...
    wta.LocalCurvaturePerMetreSquared .* spacing .^ 2, ...
    wta.ObservabilityPixelsPerMetre);
confidenceSeconds = toc(timer);

labelDiagnostics = labelReport(renderer.ImageSize, z, labelDesign, ...
    options.WorkingPrecision, p, wta, t3, sgm, refined);

bad = double(split.objective.badPixelThresholdPixels);
rawMetric = metrics(wta.HeightMetres, wta.CorrespondenceXY, wta.Valid, ...
    truthHeight, truthCorrespondence, truthValid, bad);
refinedMetric = metrics(refined.RefinedHeightMetres, ...
    refinedProjection.CorrespondenceXY, refinedProjection.Valid, ...
    truthHeight, truthCorrespondence, truthValid, bad);
sgmMetric = metrics(sgm.HeightMetres, sgmProjection.CorrespondenceXY, ...
    sgmProjection.Valid, truthHeight, truthCorrespondence, truthValid, bad);
t3Metric = metrics(t3.HeightMetres, t3.CorrespondenceXY, t3.Valid, ...
    truthHeight, truthCorrespondence, truthValid, bad);
hybridMetric = metrics(hybrid.HeightMetres, hybrid.CorrespondenceXY, ...
    hybrid.Valid, truthHeight, truthCorrespondence, truthValid, bad);

results = table(["raw-ZNCC"; "parabolic"; "frozen-SGM"; ...
    "raw-Spin2T3"; "frozen-hybrid"], ...
    [rawMetric.Coverage; refinedMetric.Coverage; sgmMetric.Coverage; ...
    t3Metric.Coverage; hybridMetric.Coverage], ...
    [rawMetric.MedianAbsoluteHeightMetres; ...
    refinedMetric.MedianAbsoluteHeightMetres; ...
    sgmMetric.MedianAbsoluteHeightMetres; ...
    t3Metric.MedianAbsoluteHeightMetres; ...
    hybridMetric.MedianAbsoluteHeightMetres], ...
    [rawMetric.HeightRmseMetres; refinedMetric.HeightRmseMetres; ...
    sgmMetric.HeightRmseMetres; t3Metric.HeightRmseMetres; ...
    hybridMetric.HeightRmseMetres], ...
    [rawMetric.MedianEpePixels; refinedMetric.MedianEpePixels; ...
    sgmMetric.MedianEpePixels; t3Metric.MedianEpePixels; ...
    hybridMetric.MedianEpePixels], ...
    [rawMetric.EpeRmsePixels; refinedMetric.EpeRmsePixels; ...
    sgmMetric.EpeRmsePixels; t3Metric.EpeRmsePixels; ...
    hybridMetric.EpeRmsePixels], ...
    [rawMetric.BadPixelFraction; refinedMetric.BadPixelFraction; ...
    sgmMetric.BadPixelFraction; t3Metric.BadPixelFraction; ...
    hybridMetric.BadPixelFraction], ...
    VariableNames=["Method", "Coverage", ...
    "MedianAbsoluteHeightMetres", "HeightRmseMetres", ...
    "MedianEpePixels", "EpeRmsePixels", "BadPixelFraction"]);
timing = table(["input/render"; "geometry/features/truth"; ...
    "dense-ZNCC"; "dense-T3/frozen-hybrid"; "parabolic"; ...
    "frozen-SGM"; "confidence"], ...
    [scene.InputSeconds; prepareSeconds; sweepSeconds; t3Seconds; ...
    refineSeconds; sgmSeconds; confidenceSeconds], ...
    VariableNames=["Stage", "Seconds"]);

requestedX = 1 + round(options.CostCurveFraction(1) ...
    .* (renderer.ImageSize(2) - 1));
requestedY = 1 + round(options.CostCurveFraction(2) ...
    .* (renderer.ImageSize(1) - 1));
[px, py] = nearestValidPixel( ...
    truthValid & wta.Valid & t3.Valid, requestedX, requestedY);
sparseCurve = curve.evaluate([px, py], z, ...
    Channels=["Zncc", "Spin2T3"], ...
    MinimumSupportFraction=minimumSupport);
znccCurve = reshape(sparseCurve.Costs.Zncc, 1, []);
t3Curve = reshape(sparseCurve.Costs.Spin2T3, 1, []);
t3ConfidenceCurve = reshape(sparseCurve.Spin2T3Confidence, 1, []);
hybridCurve = hybridModel.combine( ...
    znccCurve, t3Curve, t3ConfidenceCurve);
costCurves = struct("PixelXY", [px, py], ...
    "RequestedPixelXY", [requestedX, requestedY], ...
    "HeightLabelsMetres", z, "Zncc", znccCurve, ...
    "Spin2T3", t3Curve, ...
    "Spin2T3Confidence", t3ConfidenceCurve, ...
    "FrozenHybrid", hybridCurve, ...
    "FrozenSgm", reshape(sgm.AggregatedCost(py, px, :), 1, []));

methods = struct("RawZncc", wta, "Parabolic", refined, ...
    "ParabolicProjection", refinedProjection, "FrozenSgm", sgm, ...
    "FrozenSgmProjection", sgmProjection, "RawSpin2T3", t3, ...
    "FrozenHybrid", hybrid);
metricMaps = struct("RawZncc", rawMetric, ...
    "Parabolic", refinedMetric, "FrozenSgm", sgmMetric, ...
    "RawSpin2T3", t3Metric, "FrozenHybrid", hybridMetric);
figures = struct;
if options.Display
    figures = displayProducts(renderer, pair.ReferenceImage, ...
        pair.MovingImage, curve, truthHeight, truthValid, methods, ...
        metricMaps, confidence, referenceDouble, movingDouble, costCurves);
end

emptyVolume = zeros([renderer.ImageSize, 0]);
if options.StoreResearchCostVolumes
    t3Volume = t3.CostVolume;
    hybridVolume = wta.CostVolume ./ hybridModel.ZnccScale;
else
    t3Volume = emptyVolume;
    hybridVolume = emptyVolume;
end
report = struct( ...
    "TestNumber", scene.Number, "Identifier", scene.Identifier, ...
    "Suite", scene.Suite, "FixtureFile", scene.FixtureFile, ...
    "DatasetName", scene.DatasetName, "Radiometry", scene.Radiometry, ...
    "InputKind", scene.InputKind, "Renderer", renderer, ...
    "ReferenceImage", pair.ReferenceImage, ...
    "MovingImage", pair.MovingImage, ...
    "ReferenceValid", pair.ReferenceValid, ...
    "MovingValid", pair.MovingValid, ...
    "ReferenceFeatures", curve.Reference, ...
    "MovingFeatures", curve.Moving, ...
    "TruthHeightMetres", truthHeight, ...
    "TruthCorrespondenceXY", truthCorrespondence, ...
    "TruthValid", truthValid, "HeightLabelsMetres", z, ...
    "LabelSpacingMetres", spacing, ...
    "MedianObservabilityPixelsPerMetre", medianObservability, ...
    "HeightLabelMode", options.HeightLabelMode, ...
    "LabelDiagnostics", labelDiagnostics, ...
    "RawZncc", wta, "Parabolic", refined, ...
    "ParabolicProjection", refinedProjection, ...
    "FrozenSgm", sgm, "FrozenSgmProjection", sgmProjection, ...
    "RawSpin2T3", t3, "FrozenHybrid", hybrid, ...
    "FrozenHybridModel", hybridModel.toStruct, ...
    "Confidence", confidence, "CostCurves", costCurves, ...
    "CostVolumes", struct("Zncc", wta.CostVolume, ...
    "Spin2T3", t3Volume, "FrozenHybrid", hybridVolume), ...
    "ResearchCostVolumesStored", options.StoreResearchCostVolumes, ...
    "CpuImplementation", options.CpuImplementation, ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "SgmImplementation", sgmImplementation, ...
    "CostCurvePixelXY", [px, py], "Results", results, ...
    "Timing", timing, "Figures", figures, ...
    "TotalSeconds", toc(totalTimer), ...
    "PixelConvention", "one-based [x,y]=[column,row] centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0", ...
    "Interpolation", "bilinear; four samples required");

fprintf("Synthetic height visualization %d: %s (%s)\n", ...
    scene.Number, report.Identifier, report.Suite);
fprintf("  image %d x %d, %d-bit uint16, input %s\n", ...
    renderer.ImageSize(1), renderer.ImageSize(2), renderer.BitDepth, ...
    report.InputKind);
fprintf("  %d labels at %.6g m, median ||dw/dZ|| %.6g px/m\n", ...
    numel(z), spacing, medianObservability);
fprintf("  label mode %s; normal grid %d labels; candidate reduction %.3fx\n", ...
    options.HeightLabelMode, ...
    labelDiagnostics.ObservabilityDerivedLabelCount, ...
    labelDiagnostics.PixelLabelReductionFactor);
fprintf("  selected cost-curve pixel [x,y] = [%d,%d]\n", px, py);
fprintf("  CPU implementation %s, %s costs, %s SGM\n", ...
    options.CpuImplementation, options.WorkingPrecision, sgmImplementation);
fprintf("  T3 full volume stored: %s; frozen hybrid weights [%.3g,%.3g]\n", ...
    string(options.StoreResearchCostVolumes), ...
    hybridModel.ZnccWeight, hybridModel.Spin2Weight);
disp(results);
disp(timing);
fprintf("  total %.3f s\n", report.TotalSeconds);
end

function result = scaledZnccSelection(wta, scale)
result = struct( ...
    "HeightMetres", wta.HeightMetres, ...
    "LabelIndex", wta.LabelIndex, ...
    "BestCost", wta.BestCost ./ scale, ...
    "Valid", wta.Valid, ...
    "CorrespondenceXY", wta.CorrespondenceXY, ...
    "ObservabilityPixelsPerMetre", wta.ObservabilityPixelsPerMetre, ...
    "Regularization", ...
    "none; frozen Eq. (133) weights [1,0], exactly raw ZNCC");
end

function [z, spacing, medianObservability, diagnostic] = labels( ...
        geometry, truthHeight, valid, range, targetMotion, mode)
[y, x] = find(valid);
p = [x, y];
h = truthHeight(valid);
[~, kappa, vk] = geometry.heightDerivative(p, h, DeltaHeight=0.5);
medianObservability = median(kappa(vk));
nominalSpacing = targetMotion ./ medianObservability;
padding = max(2 .* nominalSpacing, 5);
minimum = max(range(1), ...
    floor((min(h) - padding) ./ nominalSpacing) .* nominalSpacing);
maximum = min(range(2), ...
    ceil((max(h) + padding) ./ nominalSpacing) .* nominalSpacing);
full = minimum:nominalSpacing:maximum; %#ok<BDSCI>
if numel(full) < 3
    error("runSyntheticHeightVisualization:TooFewLabels", ...
        "The observability-derived search must contain at least three labels.");
end
if mode == "three-plane"
    z = [full(1), (full(1) + full(end)) ./ 2, full(end)];
    spacing = z(2) - z(1);
else
    z = full;
    spacing = nominalSpacing;
end
diagnostic = struct( ...
    "Mode", mode, ...
    "ObservabilityDerivedHeightLabelsMetres", full, ...
    "ObservabilityDerivedLabelCount", numel(full), ...
    "NominalLabelSpacingMetres", nominalSpacing, ...
    "ExecutedHeightLabelsMetres", z, ...
    "ExecutedLabelCount", numel(z), ...
    "ExecutedAdjacentSpacingMetres", diff(z), ...
    "MedianAdjacentMotionPixels", diff(z) .* medianObservability, ...
    "PixelLabelReductionFactor", numel(full) ./ numel(z));
end

function report = labelReport(imageSize, z, design, precision, penalty, ...
        wta, t3, sgm, refined)
if precision == "single"
    bytesPerElement = 4;
else
    bytesPerElement = 8;
end
n = prod(imageSize);
adjacentPenalty = min(double(penalty.penaltyPerMetre) .* diff(z), ...
    double(penalty.maximumPenalty));
selection = table;
if numel(z) == 3
    selection = [selectionFractions("raw-ZNCC", wta); ...
        selectionFractions("frozen-SGM", sgm); ...
        selectionFractions("raw-Spin2T3", t3)];
end
validRaw = nnz(wta.Valid);
if validRaw == 0
    refinementFraction = NaN;
else
    refinementFraction = nnz(refined.Valid & wta.Valid) ./ validRaw;
end
report = design;
report.WorkingCostBytesPerElement = bytesPerElement;
report.ExecutedCostVolumeBytes = n .* numel(z) .* bytesPerElement;
report.ObservabilityGridCostVolumeBytes = n ...
    .* design.ObservabilityDerivedLabelCount .* bytesPerElement;
report.ExecutedCostVolumeMiB = report.ExecutedCostVolumeBytes ./ 2 ^ 20;
report.ObservabilityGridCostVolumeMiB = ...
    report.ObservabilityGridCostVolumeBytes ./ 2 ^ 20;
report.SgmAdjacentTransitionCost = adjacentPenalty;
report.SgmAdjacentTransitionCapped = adjacentPenalty ...
    >= double(penalty.maximumPenalty);
report.AllSgmAdjacentTransitionsCapped = ...
    all(report.SgmAdjacentTransitionCapped);
report.RefinementValidFractionOfRaw = refinementFraction;
report.SelectionFractions = selection;
report.MemoryDefinition = ...
    "one dense [row,column,label] working-precision volume";
if design.Mode == "three-plane"
    report.ConfidenceCalibrationStatus = ...
        "diagnostic only; three-plane spacing was not used to fit calibration";
else
    report.ConfidenceCalibrationStatus = "frozen calibrated grid";
end
end

function row = selectionFractions(name, result)
valid = result.Valid & result.LabelIndex >= 1 ...
    & result.LabelIndex <= 3;
count = nnz(valid);
fractions = nan(1, 3);
if count > 0
    fractions = [nnz(result.LabelIndex(valid) == 1), ...
        nnz(result.LabelIndex(valid) == 2), ...
        nnz(result.LabelIndex(valid) == 3)] ./ count;
end
row = table(name, nnz(valid) ./ numel(valid), fractions(1), ...
    fractions(2), fractions(3), VariableNames=["Method", ...
    "ValidPixelFraction", "MinimumWinnerFraction", ...
    "MidpointWinnerFraction", "MaximumWinnerFraction"]);
end

function [px, py] = nearestValidPixel(valid, requestedX, requestedY)
[y, x] = find(valid);
if isempty(x)
    px = requestedX;
    py = requestedY;
    return
end
[~, k] = min((x - requestedX) .^ 2 + (y - requestedY) .^ 2);
px = x(k);
py = y(k);
end

function result = metrics(h, w, valid, truthHeight, truthW, truthValid, bad)
valid = valid & truthValid & isfinite(h) ...
    & isfinite(w(:, :, 1)) & isfinite(w(:, :, 2));
heightError = nan(size(h));
epe = nan(size(h));
heightError(valid) = h(valid) - truthHeight(valid);
wx = w(:, :, 1);
wy = w(:, :, 2);
tx = truthW(:, :, 1);
ty = truthW(:, :, 2);
epe(valid) = hypot(wx(valid) - tx(valid), wy(valid) - ty(valid));
result = struct( ...
    "Coverage", nnz(valid) ./ max(nnz(truthValid), 1), ...
    "MedianAbsoluteHeightMetres", median(abs(heightError(valid))), ...
    "HeightRmseMetres", sqrt(mean(heightError(valid) .^ 2)), ...
    "MedianEpePixels", median(epe(valid)), ...
    "EpeRmsePixels", sqrt(mean(epe(valid) .^ 2)), ...
    "BadPixelFraction", mean(epe(valid) > bad), ...
    "HeightErrorMetres", heightError, "EpePixels", epe, ...
    "Valid", valid);
end

function figures = displayProducts(renderer, reference, moving, curve, ...
        truthHeight, truthValid, methods, metricMaps, confidence, ...
        referenceDouble, movingDouble, costCurves)
% Inputs use viewer2d/imageshow; quantitative fields use unit-bearing maps.
tile = imtile(cat(4, reference, moving), GridSize=[1, 2]);
viewer = viewer2d;
imageshow(tile, Parent=viewer, DisplayRangeMode="data-range");
title(viewer, sprintf("%s: reference (left), moving (right)", ...
    renderer.Identifier));

featureFigure = figure(Name=renderer.Identifier + " intermediates", ...
    Color="white");
layout = tiledlayout(featureFigure, 2, 5, TileSpacing="compact", ...
    Padding="compact");
showMap(nexttile(layout), abs(curve.Reference.G), ...
    "Reference |gradient|", "parula");
showMap(nexttile(layout), abs(curve.Moving.G), ...
    "Moving |gradient|", "parula");
showMap(nexttile(layout), curve.Reference.Coherence, ...
    "Reference spin-2 coherence", "parula");
showMap(nexttile(layout), curve.Moving.Coherence, ...
    "Moving spin-2 coherence", "parula");
showMap(nexttile(layout), methods.RawZncc.BestCost, ...
    "ZNCC best cost", "parula");
showMap(nexttile(layout), methods.RawZncc.CostMargin, ...
    "ZNCC second-label margin", "parula");
showMap(nexttile(layout), ...
    methods.RawZncc.LocalCurvaturePerMetreSquared, ...
    "ZNCC curvature (cost/m^2)", "parula");
showMap(nexttile(layout), methods.RawSpin2T3.BestCost, ...
    "T3 best cost", "parula");
showMap(nexttile(layout), methods.RawSpin2T3.CostMargin, ...
    "T3 second-label margin", "parula");
showMap(nexttile(layout), ...
    methods.RawZncc.ObservabilityPixelsPerMetre, ...
    "||dw/dZ|| (pixel/m)", "parula");
label = title(layout, renderer.Identifier + " intermediate products");
label.Color = "black";

methodFigure = figure(Name=renderer.Identifier + " method outputs", ...
    Color="white");
layout = tiledlayout(methodFigure, 2, 4, TileSpacing="compact", ...
    Padding="compact");
heightLimits = finiteLimits(truthHeight(truthValid));
showMap(nexttile(layout), truthHeight, "Truth height (m)", ...
    "turbo", heightLimits);
showMap(nexttile(layout), methods.RawZncc.HeightMetres, ...
    "Raw ZNCC height (m)", "turbo", heightLimits);
showMap(nexttile(layout), methods.Parabolic.RefinedHeightMetres, ...
    "Parabolic height (m)", "turbo", heightLimits);
showMap(nexttile(layout), methods.FrozenSgm.HeightMetres, ...
    "Frozen SGM height (m)", "turbo", heightLimits);
showMap(nexttile(layout), methods.RawSpin2T3.HeightMetres, ...
    "Raw transported T3 height (m)", "turbo", heightLimits);
showMap(nexttile(layout), methods.FrozenHybrid.HeightMetres, ...
    "Frozen hybrid [1,0] height (m)", "turbo", heightLimits);
showMap(nexttile(layout), confidence.SigmaHeightMetres, ...
    "Predicted height sigma (m)", "parula");
showMap(nexttile(layout), double(truthValid) ...
    + 2 .* double(methods.RawZncc.Valid) ...
    + 4 .* double(methods.FrozenSgm.Valid) ...
    + 8 .* double(methods.RawSpin2T3.Valid), ...
    "Masks: truth + 2 raw + 4 SGM + 8 T3", "parula", [0, 15]);
label = title(layout, renderer.Identifier + " height outputs");
label.Color = "black";

errorFigure = figure(Name=renderer.Identifier + " errors", Color="white");
layout = tiledlayout(errorFigure, 2, 5, TileSpacing="compact", ...
    Padding="compact");
names = ["Raw ZNCC", "Parabolic", "Frozen SGM", ...
    "Raw T3", "Frozen hybrid"];
fields = ["RawZncc", "Parabolic", "FrozenSgm", ...
    "RawSpin2T3", "FrozenHybrid"];
for k = 1:numel(fields)
    m = metricMaps.(fields(k));
    showMap(nexttile(layout), m.HeightErrorMetres, ...
        names(k) + " height error (m)", "balance");
end
for k = 1:numel(fields)
    m = metricMaps.(fields(k));
    showMap(nexttile(layout), m.EpePixels, ...
        names(k) + " endpoint error (pixel)", "hot");
end
label = title(layout, renderer.Identifier + " truth errors");
label.Color = "black";

rawMoving = warpMoving(movingDouble, ...
    methods.RawZncc.CorrespondenceXY, methods.RawZncc.Valid);
sgmMoving = warpMoving(movingDouble, ...
    methods.FrozenSgmProjection.CorrespondenceXY, ...
    methods.FrozenSgmProjection.Valid);
t3Moving = warpMoving(movingDouble, ...
    methods.RawSpin2T3.CorrespondenceXY, methods.RawSpin2T3.Valid);
hybridMoving = warpMoving(movingDouble, ...
    methods.FrozenHybrid.CorrespondenceXY, methods.FrozenHybrid.Valid);
alignmentFigure = figure(Name=renderer.Identifier + " alignment", ...
    Color="white");
layout = tiledlayout(alignmentFigure, 2, 5, TileSpacing="compact", ...
    Padding="compact");
showMap(nexttile(layout), referenceDouble, "Reference", "gray", [0, 1]);
showMap(nexttile(layout), rawMoving, "Moving at raw ZNCC", "gray", [0, 1]);
showMap(nexttile(layout), sgmMoving, "Moving at frozen SGM", "gray", [0, 1]);
showMap(nexttile(layout), t3Moving, "Moving at raw T3", "gray", [0, 1]);
showMap(nexttile(layout), hybridMoving, ...
    "Moving at frozen hybrid", "gray", [0, 1]);
showMap(nexttile(layout), movingDouble, "Original moving", "gray", [0, 1]);
showMap(nexttile(layout), abs(referenceDouble - rawMoving), ...
    "|reference - raw ZNCC warp|", "hot");
showMap(nexttile(layout), abs(referenceDouble - sgmMoving), ...
    "|reference - frozen SGM warp|", "hot");
showMap(nexttile(layout), abs(referenceDouble - t3Moving), ...
    "|reference - raw T3 warp|", "hot");
ax = nexttile(layout);
plotCostCurves(ax, costCurves);
title(ax, sprintf("Cost curves at [x,y]=[%d,%d]", ...
    costCurves.PixelXY), Color="black");
label = title(layout, renderer.Identifier + " alignment products");
label.Color = "black";
drawnow;

figures = struct("InputViewer", viewer, ...
    "IntermediateFigure", featureFigure, ...
    "MethodFigure", methodFigure, "ErrorFigure", errorFigure, ...
    "AlignmentFigure", alignmentFigure);
end

function out = warpMoving(moving, correspondence, valid)
x = correspondence(:, :, 1);
y = correspondence(:, :, 2);
out = interp2(moving, x, y, "linear", NaN);
out(~valid) = NaN;
end

function showMap(ax, value, label, color, limits)
arguments
    ax (1, 1) matlab.graphics.axis.Axes
    value (:, :) double
    label (1, 1) string
    color (1, 1) string
    limits (1, 2) double = [NaN, NaN]
end
imagesc(ax, value);
axis(ax, "image");
set(ax, YDir="reverse", Color=[0.25, 0.25, 0.25], ...
    XColor="black", YColor="black");
title(ax, label, Interpreter="none", Color="black");
bar = colorbar(ax);
bar.Color = "black";
if color == "balance"
    m = max(abs(value(isfinite(value))), [], "all");
    if isempty(m) || m == 0
        m = 1;
    end
    colormap(ax, blueWhiteRed(256));
    clim(ax, [-m, m]);
else
    colormap(ax, color);
end
if all(isfinite(limits)) && limits(1) < limits(2)
    clim(ax, limits);
end
end

function limits = finiteLimits(value)
value = value(isfinite(value));
limits = [min(value), max(value)];
if limits(1) == limits(2)
    limits = limits + [-1, 1];
end
end

function plotCostCurves(ax, curves)
z = curves.HeightLabelsMetres;
hold(ax, "on");
set(ax, Color="white", XColor="black", YColor="black");
plot(ax, z, normalizeCurve(curves.Zncc), ...
    LineWidth=1.5, DisplayName="ZNCC");
plot(ax, z, normalizeCurve(curves.Spin2T3), ...
    LineWidth=1.5, DisplayName="T3");
plot(ax, z, normalizeCurve(curves.FrozenHybrid), ...
    LineWidth=1.5, DisplayName="frozen hybrid [1,0]");
plot(ax, z, normalizeCurve(curves.FrozenSgm), ...
    LineWidth=1.5, DisplayName="frozen SGM");
grid(ax, "on");
xlabel(ax, "Height (m)");
ylabel(ax, "Per-curve normalized cost");
key = legend(ax, Location="best");
key.Color = "white";
key.TextColor = "black";
end

function y = normalizeCurve(x)
y = nan(size(x));
valid = isfinite(x);
if ~any(valid)
    return
end
minimum = min(x(valid));
range = max(x(valid)) - minimum;
if range == 0
    y(valid) = 0;
else
    y(valid) = (x(valid) - minimum) ./ range;
end
end

function map = blueWhiteRed(n)
t = linspace(0, 1, n).';
map = [min(1, 2 .* t), 1 - 2 .* abs(t - 0.5), ...
    min(1, 2 .* (1 - t))];
end

function mustBeVisualizationScene(scene)
required = ["Number", "Identifier", "Suite", "FixtureFile", ...
    "DatasetName", "Radiometry", "InputKind", "Renderer", "Pair", ...
    "TruthHeightMetres", "TruthCorrespondenceXY", "TruthValid", ...
    "SearchRangeMetres", "TargetMotionPerLabelPixels", ...
    "Configuration", "InputSeconds"];
missing = required(~isfield(scene, required));
if ~isempty(missing)
    error("runSyntheticHeightVisualization:IncompleteScene", ...
        "Visualization scene is missing field(s): %s", ...
        strjoin(missing, ", "));
end
imageSize = scene.Renderer.ImageSize;
if ~isequal(size(scene.Pair.ReferenceImage), imageSize) ...
        || ~isequal(size(scene.Pair.MovingImage), imageSize) ...
        || ~isequal(size(scene.Pair.ReferenceValid), imageSize) ...
        || ~isequal(size(scene.Pair.MovingValid), imageSize) ...
        || ~isequal(size(scene.TruthHeightMetres), imageSize) ...
        || ~isequal(size(scene.TruthCorrespondenceXY), [imageSize, 2]) ...
        || ~isequal(size(scene.TruthValid), imageSize)
    error("runSyntheticHeightVisualization:SceneSizeMismatch", ...
        "Images, masks, and truth must match the renderer image size.");
end
end
